/* 1. iOS Switch Style CSS */
.switch-ios {
  position: relative;
  display: inline-block;
  width: 52px;
  height: 32px;
}

.switch-ios input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider-ios {
  position: absolute;
  cursor: pointer;
  top: 0; left: 0; right: 0; bottom: 0;
  background-color: #cbd5e1;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 32px;
}

.slider-ios::before {
  content: "";
  position: absolute;
  height: 28px;
  width: 28px;
  left: 2px;
  bottom: 2px;
  background-color: white;
  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1.1);
  border-radius: 50%;
  box-shadow: 0 3px 8px rgba(0, 0, 0, 0.15);
}

.switch-ios input:checked + .slider-ios {
  background-color: #34c759; /* iOS green */
}

.switch-ios input:checked + .slider-ios::before {
  transform: translateX(20px);
}
